+fn write_json(path: &Path, value: &serde_json::Value) {
+    if let Some(parent) = path.parent() {
+        std::fs::create_dir_all(parent).expect("create parent dirs");
+    }
+    std::fs::write(
+        path,
+        serde_json::to_string_pretty(value).expect("serialize json"),
+    )
+    .expect("write json");
+}
